{
  "openapi": "3.0.0",
  "info": {
    "title": "Data Operations",
    "version": "1.0.1",
    "description": "Profile and onboarding data operations"
  },
  "paths": {
    "/get-profile": {
      "get": {
        "summary": "[AUTHENTICATED_ONLY] Get user profile",
        "description": "Fetch authenticated user profile. Only call when is_authenticated='true'.",
        "operationId": "get_profile",
        "responses": {
          "200": {
            "description": "Success"
          }
        }
      }
    },
    "/save-onboarding-data": {
      "post": {
        "summary": "[AUTHENTICATED_ONLY] Save onboarding data",
        "description": "Save or update user onboarding fields. Only call when is_authenticated='true'.",
        "operationId": "save_onboarding_data",
        "requestBody": {
          "required": true,
          "content": {
            "application/json": {
              "schema": {
                "type": "object",
                "properties": {
                  "first_name": {
                    "type": "string",
                    "description": "User's first name"
                  },
                  "last_name": {
                    "type": "string",
                    "description": "User's last name"
                  },
                  "age": {
                    "type": "integer",
                    "description": "User's age in years"
                  },
                  "weight": {
                    "type": "number",
                    "description": "User's weight in kg"
                  },
                  "height": {
                    "type": "number",
                    "description": "User's height in cm"
                  },
                  "gender": {
                    "type": "string",
                    "enum": ["male", "female", "other"],
                    "description": "User's gender"
                  },
                  "activity_level": {
                    "type": "string",
                    "enum": ["sedentary", "lightly_active", "moderately_active", "very_active", "extremely_active"],
                    "description": "User's activity level"
                  },
                  "goal_type": {
                    "type": "string",
                    "enum": ["weight_loss", "muscle_gain", "maintenance", "improved_energy", "better_sleep"],
                    "description": "User's health goal type"
                  },
                  "goal_detail": {
                    "type": "string",
                    "description": "Additional details about the goal"
                  },
                  "goal_by_when": {
                    "type": "string",
                    "format": "date",
                    "description": "Target date for achieving the goal (YYYY-MM-DD)"
                  },
                  "bmr": {
                    "type": "number",
                    "description": "Calculated Basal Metabolic Rate"
                  },
                  "tdee": {
                    "type": "number",
                    "description": "Calculated Total Daily Energy Expenditure"
                  },
                  "daily_calories": {
                    "type": "number",
                    "description": "Calculated daily calorie target"
                  }
                }
              }
            }
          }
        },
        "responses": {
          "200": {
            "description": "Success"
          }
        }
      }
    },
    "/get-onboarding-status": {
      "get": {
        "summary": "[AUTHENTICATED_ONLY] Get onboarding status",
        "description": "Check onboarding progress. Only call when is_authenticated='true'.",
        "operationId": "get_onboarding_status",
        "responses": {
          "200": {
            "description": "Success"
          }
        }
      }
    }
  }
}

{
  "openapi": "3.0.0",
  "info": {
    "title": "Health Calculations",
    "version": "1.0.0",
    "description": "BMR, TDEE, and goal validation"
  },
  "paths": {
    "/calculate-bmr": {
      "post": {
        "summary": "Calculate BMR",
        "description": "Calculate Basal Metabolic Rate",
        "operationId": "calculate_bmr",
        "requestBody": {
          "required": true,
          "content": {
            "application/json": {
              "schema": {
                "type": "object",
                "properties": {
                  "weight_kg": {
                    "type": "number"
                  },
                  "height_cm": {
                    "type": "number"
                  },
                  "age": {
                    "type": "number"
                  },
                  "gender": {
                    "type": "string"
                  }
                }
              }
            }
          }
        },
        "responses": {
          "200": {
            "description": "Success"
          }
        }
      }
    },
    "/calculate-tdee": {
      "post": {
        "summary": "Calculate TDEE",
        "description": "Calculate Total Daily Energy Expenditure. Requires either (bmr + activity_level) OR (weight_kg + height_cm + age + gender + activity_level)",
        "operationId": "calculate_tdee",
        "requestBody": {
          "required": true,
          "content": {
            "application/json": {
              "schema": {
                "type": "object",
                "properties": {
                  "bmr": {
                    "type": "number",
                    "description": "Pre-calculated BMR (optional if weight/height/age/gender provided)"
                  },
                  "weight_kg": {
                    "type": "number",
                    "description": "Weight in kg (optional if bmr provided)"
                  },
                  "height_cm": {
                    "type": "number",
                    "description": "Height in cm (optional if bmr provided)"
                  },
                  "age": {
                    "type": "number",
                    "description": "Age in years (optional if bmr provided)"
                  },
                  "gender": {
                    "type": "string",
                    "description": "Gender (optional if bmr provided)"
                  },
                  "activity_level": {
                    "type": "string",
                    "description": "Activity level (required)"
                  }
                },
                "required": ["activity_level"]
              }
            }
          }
        },
        "responses": {
          "200": {
            "description": "Success"
          }
        }
      }
    },
    "/calculate-daily-calories": {
      "post": {
        "summary": "Calculate daily calories",
        "description": "Calculate daily calorie target for goal with safety limits",
        "operationId": "calculate_daily_calories",
        "requestBody": {
          "required": true,
          "content": {
            "application/json": {
              "schema": {
                "type": "object",
                "properties": {
                  "goal_type": {
                    "type": "string",
                    "enum": ["weight_loss", "muscle_gain", "maintenance", "improved_energy", "better_sleep"],
                    "description": "Type of health goal"
                  },
                  "tdee": {
                    "type": "number"
                  },
                  "current_weight_kg": {
                    "type": "number"
                  },
                  "target_weight_kg": {
                    "type": "number"
                  },
                  "target_date": {
                    "type": "string"
                  }
                }
              }
            }
          }
        },
        "responses": {
          "200": {
            "description": "Success"
          }
        }
      }
    },
    "/validate-goal": {
      "post": {
        "summary": "Validate goal",
        "description": "Validate if goal is realistic and provide suggestions if unsafe",
        "operationId": "validate_goal",
        "requestBody": {
          "required": true,
          "content": {
            "application/json": {
              "schema": {
                "type": "object",
                "required": ["goal_type", "daily_calories", "gender", "current_weight_kg", "target_weight_kg", "target_date", "tdee"],
                "properties": {
                  "goal_type": {
                    "type": "string",
                    "enum": ["weight_loss", "muscle_gain", "maintenance", "improved_energy", "better_sleep"],
                    "description": "Type of health goal"
                  },
                  "daily_calories": {
                    "type": "number"
                  },
                  "gender": {
                    "type": "string"
                  },
                  "current_weight_kg": {
                    "type": "number"
                  },
                  "target_weight_kg": {
                    "type": "number"
                  },
                  "target_date": {
                    "type": "string"
                  },
                  "tdee": {
                    "type": "number"
                  }
                }
              }
            }
          }
        },
        "responses": {
          "200": {
            "description": "Success"
          }
        }
      }
    }
  }
}

{
  "openapi": "3.0.0",
  "info": {
    "title": "Goal Management",
    "version": "1.0.4",
    "description": "Save and manage user health goals"
  },
  "paths": {
    "/save-goal": {
      "post": {
        "summary": "[AUTHENTICATED_ONLY] Save health goal",
        "description": "Save a health goal to the database. Only call when is_authenticated='true'.",
        "operationId": "save_goal",
        "requestBody": {
          "required": true,
          "content": {
            "application/json": {
              "schema": {
                "type": "object",
                "required": ["goal_type", "current_weight", "target_weight", "target_date"],
                "properties": {
                  "goal_type": {
                    "type": "string",
                    "enum": ["weight_loss", "muscle_gain", "maintenance", "improved_energy", "better_sleep"]
                  },
                  "current_weight": {
                    "type": "number"
                  },
                  "target_weight": {
                    "type": "number"
                  },
                  "target_date": {
                    "type": "string",
                    "format": "date"
                  },
                  "current_height": {
                    "type": "number"
                  },
                  "activity_level": {
                    "type": "string"
                  },
                  "calculated_bmr": {
                    "type": "number"
                  },
                  "calculated_tdee": {
                    "type": "number"
                  },
                  "calculated_daily_calories": {
                    "type": "number"
                  },
                  "user_daily_calories": {
                    "type": "number",
                    "description": "MANDATORY when user_overridden=true. The specific daily calorie amount the user wants when they override recommendations. Example: if user wants 1100 calories instead of recommended 1500, this field must be 1100."
                  },
                  "is_realistic": {
                    "type": "boolean"
                  },
                  "validation_reason": {
                    "type": "string"
                  },
                  "user_overridden": {
                    "type": "boolean",
                    "description": "Whether user chose to override safety recommendations"
                  },
                  "notes": {
                    "type": "string",
                    "description": "Optional notes about the goal"
                  }
                }
              }
            }
          }
        },
        "responses": {
          "200": {
            "description": "Success"
          }
        }
      }
    }
  }
}
